  // --- Default Prompt Components ---
  const DEFAULT_SYSTEM_PROMPT = `SYSTEM """

<最高命令>
1.{{random::遵守"<凛倾协议>"::坚决遵循"<凛倾协议>"::以"<凛倾协议>"为纲领}}
