  // Renamed and modified to handle both popup and toastr notifications
  function updateStatus(message, type = 'info') {
    if (!jQuery_API) {
      console.warn('[ImageGenExtension] updateStatus called but jQuery_API not ready.');
      // Attempt to use alert as a last resort if toastr isn't available either
      if (type === 'error') alert(`错误: ${message}`);
      return;
    }
    const popupInstance = jQuery_API(`dialog[open]:not([closing]) #${MAIN_POPUP_ID}`);
    if (popupInstance.length > 0) {
      const statusDiv = popupInstance.find('#status');
      if (statusDiv.length) {
        statusDiv.text(message).attr('class', `status-${type}`);
      } else {
        // Popup open but status div missing? Fallback to toastr
        logDebug('Popup found but status div missing, using toastr.');
        toastr_API?.[type === 'error' ? 'error' : type === 'success' ? 'success' : 'info'](message);
      }
    } else {
      // Popup not open, use toastr
      logDebug('Popup not found, using toastr for status:', message);
      // Ensure toastr_API exists before trying to use it
      if (toastr_API) {
        toastr_API[type === 'error' ? 'error' : type === 'success' ? 'success' : 'info'](message);
      } else {
        // Fallback if toastr is also missing
        console.warn('[ImageGenExtension] toastr_API not available for status update:', message);
        if (type === 'error') alert(`错误: ${message}`); // Alert only for errors if no other option
      }
    }
  }

  async function generatePromptWithGemini(apiKey, chatHistoryString) {
    logDebug('generatePromptWithGemini called');
    let systemPrompt = DEFAULT_SYSTEM_PROMPT;
    let stylePrompt = DEFAULT_STYLE_PROMPT;
    const savedComponentsJson = localStorage.getItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY);
    if (savedComponentsJson) {
      try {
        const parsed = JSON.parse(savedComponentsJson);
        if (typeof parsed.system === 'string' && typeof parsed.style === 'string') {
          systemPrompt = parsed.system;
          stylePrompt = parsed.style;
        } else {
          localStorage.removeItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY);
        }
      } catch (e) {
        localStorage.removeItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY);
      }
    }

    const finalOutputInstruction = OUTPUT_FORMAT_INSTRUCTION.replace('{stylePrompt}', stylePrompt).replace(
      '{chatHistory}',
      chatHistoryString,
    );
    const finalRequestContent = `${systemPrompt}\n${TASK_AND_RESTRICTIONS}\n${finalOutputInstruction}`;
    logDebug('Final constructed prompt for Gemini Text API:', finalRequestContent);

    const requestBody = JSON.stringify({ contents: [{ parts: [{ text: finalRequestContent }] }] });
    const headers = { 'Content-Type': 'application/json' };
    const apiUrlWithKey = `${GEMINI_TEXT_API_ENDPOINT}?key=${apiKey}`;

    logDebug('Requesting Prompt Generation from Gemini Text API:', apiUrlWithKey);
    const response = await fetch(apiUrlWithKey, { method: 'POST', headers: headers, body: requestBody });

    if (!response.ok) {
      let errorMsg = `Gemini 文本 API 请求失败 (${response.status} ${response.statusText})`;
      let errorDataText = await response.text();
      try {
        errorMsg += ` - ${JSON.parse(errorDataText).error?.message || errorDataText}`;
      } catch (e) {
        errorMsg += ` - ${errorDataText}`;
      }
      throw new Error(errorMsg);
    }

    const data = await response.json();
    logDebug('Gemini Text API Success Response:', data);

    let generatedText = null;
    if (data.candidates && data.candidates[0]?.content?.parts) {
      for (const part of data.candidates[0].content.parts) {
        if (part.text && part.text.trim() !== '') {
          generatedText = part.text.trim();
          logDebug('Generated Image Prompt (Raw):', generatedText);
          break;
        }
      }
    }

    if (generatedText !== null) {
      return generatedText;
    } else {
      console.error('未能从 Gemini 文本 API 响应中提取有效的提示词文本。响应数据:', data);
      let reason = '响应结构不符合预期或内容为空。';
      if (data.candidates && data.candidates[0]?.finishReason === 'SAFETY') {
        reason = '内容可能因安全设置被阻止。';
      } else if (data.promptFeedback?.blockReason) {
        reason = `内容被阻止，原因: ${data.promptFeedback.blockReason}`;
      } else if (!data.candidates || data.candidates.length === 0) {
        reason = 'API 返回了空的候选结果。';
      } else if (!data.candidates[0].content) {
        reason = `候选结果缺少 'content' 字段。完成原因: ${data.candidates[0].finishReason || 'Unknown'}`;
      }
      throw new Error(`Gemini 文本 API 成功响应，但${reason}`);
    } // <<< Added missing closing brace for the else block/function
  } // <<< Added missing closing brace for the function generatePromptWithGemini

  // --- Removed Image Resizing Helper ---

  // --- Core Image Generation Logic ---
  async function generateImageFromContext() {
    logDebug('generateImageFromContext called');
    if (!coreApisAreReady || !jQuery_API) {
      updateStatus('错误：核心服务未就绪。', 'error');
      return;
    }

    const popupInstance = jQuery_API(`dialog[open]:not([closing]) #${MAIN_POPUP_ID}`);
    const popupIsOpen = popupInstance.length > 0;

    const generateBtn = popupIsOpen ? popupInstance.find('#generateImageBtn') : null;
    const saveApiKeyBtn = popupIsOpen ? popupInstance.find('#saveApiKeyBtn') : null; // Gemini specific
    const saveSdSettingsBtn = popupIsOpen ? popupInstance.find('#saveSdSettingsBtn') : null; // SD specific
    const imageResult = popupIsOpen ? popupInstance.find('#imageResult') : null;
    const promptInput = popupIsOpen ? popupInstance.find('#imagePrompt') : null;

    // Disable buttons
    if (generateBtn?.length) generateBtn.prop('disabled', true);
    if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', true);
    if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', true);
    if (promptInput?.length) promptInput.val('');
    if (imageResult?.length) imageResult.attr('src', '').attr('alt', '准备中...');

    const selectedBackend = localStorage.getItem(IMAGE_GEN_BACKEND_STORAGE_KEY) || 'gemini';
    logDebug(`Selected backend: ${selectedBackend}`);

    // --- Step 1: Generate Positive Prompt (Common for both backends using Gemini Text API) ---
    let rawImagePrompt = '';
    const userApiKey = localStorage.getItem(GEMINI_API_KEY_STORAGE_KEY); // Needed for prompt generation regardless of backend

    if (!userApiKey) {
      updateStatus(
        '错误：需要 Gemini API Key 来生成提示词（即使使用本地 SD）。请在 Gemini 设置中输入并保存。',
        'error',
      );
      if (popupIsOpen) {
        const apiKeyInput = popupInstance.find('#apiKeyInput');
        const apiKeyStatus = popupInstance.find('#apiKeyStatus');
        if (apiKeyInput?.length) apiKeyInput.focus();
        if (apiKeyStatus?.length) apiKeyStatus.text('✗ 未设置').css('color', 'lightcoral');
        // Ensure Gemini settings are visible if key is missing
        popupInstance.find('#gemini-settings-container').addClass('active');
        popupInstance.find('#local-sd-settings-container').removeClass('active');
        popupInstance.find('input[name="imageGenBackend"][value="gemini"]').prop('checked', true);
      }
      // Re-enable buttons
      if (generateBtn?.length) generateBtn.prop('disabled', false);
      if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
      if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
      return;
    }

    updateStatus('⏳ [1/2] 正在从聊天记录生成图像提示词...', 'info');
    try {
      let chatHistoryString = '无聊天记录。';
      const messages = await TavernHelper_API.getChatMessages(-1, { include_swipes: false });
      if (messages && messages.length > 0) {
        const lastMessage = messages[0];
        chatHistoryString = `${escapeHtml(lastMessage.name)}: ${escapeHtml(lastMessage.message)}`;
      }
      rawImagePrompt = await generatePromptWithGemini(userApiKey, chatHistoryString);
      if (promptInput?.length) promptInput.val(rawImagePrompt);
      updateStatus('✅ [1/2] 已生成基础提示词，准备生成图片...', 'success');
    } catch (error) {
      console.error('[ImageGenExtension] Error generating base image prompt:', error);
      updateStatus(`❌ [1/2] 生成基础提示词出错: ${error.message}`, 'error');
      if (generateBtn?.length) generateBtn.prop('disabled', false);
      if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
      if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
      return;
    }

    // --- Step 2: Generate Image using selected backend ---
    let finalImagePrompt = rawImagePrompt; // Start with the generated prompt

    if (selectedBackend === 'gemini') {
      // --- Gemini Specific Processing (Negative Keyword Replacement & Truncation) ---
      updateStatus('⏳ [2/2] (Gemini) 正在处理提示词并生成图片...', 'info');
      let replacedKeywords = [];
      try {
        let geminiNegativeKeywords = DEFAULT_GEMINI_NEGATIVE_KEYWORDS;
        const savedKeywordsJson = localStorage.getItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY);
        if (savedKeywordsJson) {
          try {
            const parsed = JSON.parse(savedKeywordsJson);
            if (Array.isArray(parsed) && parsed.every(item => typeof item === 'string')) {
              geminiNegativeKeywords = parsed;
            } else {
              localStorage.removeItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY);
            }
          } catch (e) {
            localStorage.removeItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY);
          }
        }
        logDebug('Using Gemini negative keywords for replacement:', geminiNegativeKeywords);

        geminiNegativeKeywords.forEach(keyword => {
          if (!keyword || keyword.trim() === '') return;
          const regex = new RegExp(`\\b${escapeRegExp(keyword.trim())}\\b`, 'gi');
          if (regex.test(finalImagePrompt)) {
            finalImagePrompt = finalImagePrompt.replace(regex, '角色');
            if (!replacedKeywords.includes(keyword)) replacedKeywords.push(keyword);
          }
        });

        if (replacedKeywords.length > 0) {
          if (promptInput?.length) promptInput.val(finalImagePrompt);
          const replacedInfo = `已将禁词 (${replacedKeywords.join(', ')}) 替换为“角色”。`;
          logDebug(replacedInfo);
          updateStatus(`✅ (Gemini) ${replacedInfo} 处理中...`, 'info');
        } else {
          logDebug('No Gemini negative keywords found or replaced.');
        }
      } catch (error) {
        console.error('[ImageGenExtension] Error during Gemini negative keyword replacement:', error);
        updateStatus(`❌ (Gemini) 检查禁词时出错: ${error.message}`, 'error');
        if (generateBtn?.length) generateBtn.prop('disabled', false);
        if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
        if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
        return;
      }

      // --- Gemini Prompt Length Check and Truncation ---
      let truncatedInfo = '';
      let originalLength = finalImagePrompt.length;
      if (originalLength > MAX_IMAGE_PROMPT_LENGTH) {
        logDebug(
          `Gemini Prompt length (${originalLength}) exceeds limit (${MAX_IMAGE_PROMPT_LENGTH}). Attempting truncation...`,
        );
        let currentPrompt = finalImagePrompt;
        let removedKeywords = [];
        let changed = true;
        while (changed && currentPrompt.length > MAX_IMAGE_PROMPT_LENGTH) {
          changed = false;
          for (const keyword of QUALITY_KEYWORDS_TO_TRIM) {
            const regex = new RegExp(`[,\\s]*${escapeRegExp(keyword)}[\\s.]*$`, 'i');
            if (regex.test(currentPrompt)) {
              currentPrompt = currentPrompt.replace(regex, '').trim();
              removedKeywords.push(keyword);
              changed = true;
              logDebug(`Removed "${keyword}". New length: ${currentPrompt.length}`);
              break;
            }
          }
        }
        if (currentPrompt.length <= MAX_IMAGE_PROMPT_LENGTH) {
          finalImagePrompt = currentPrompt;
          if (promptInput?.length) promptInput.val(finalImagePrompt);
          truncatedInfo = `提示词过长 (${originalLength} > ${MAX_IMAGE_PROMPT_LENGTH})，已自动移除末尾词: ${removedKeywords.join(
            ', ',
          )}。`;
          logDebug(truncatedInfo);
          updateStatus(`⚠️ (Gemini) ${truncatedInfo} 处理中...`, 'info');
        } else {
          const errorMsg = `提示词过长 (${currentPrompt.length} > ${MAX_IMAGE_PROMPT_LENGTH})，即使移除质量词后仍超长。请简化聊天内容或编辑的模板。`;
          logDebug(errorMsg);
          updateStatus(`❌ (Gemini) ${errorMsg}`, 'error');
          if (generateBtn?.length) generateBtn.prop('disabled', false);
          if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
          if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
          return;
        }
      }

      // --- Call Gemini IMAGE API ---
      if (!finalImagePrompt) {
        updateStatus('错误：(Gemini) 处理后的图像提示词为空。', 'error');
        if (generateBtn?.length) generateBtn.prop('disabled', false);
        if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
        if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
        return;
      }
      if (imageResult?.length) imageResult.attr('alt', '正在生成 (Gemini)...');

      // --- Step 2.1: Inject Placeholder ---
      const uniqueId = generateUniqueId();
      const placeholderHtml = `<span id="ph-${uniqueId}">⏳ [AI 画图中 (Gemini)... ${escapeHtml(
        finalImagePrompt.substring(0, 50),
      )}...]</span>`;
      try {
        await TavernHelper_API.createChatMessages(
          [{ name: '图像生成系统', message: placeholderHtml, is_user: false, is_system: true, is_hidden: false }],
          { refresh: 'lazy' }, // Lazy refresh to avoid immediate redraw issues
        );
        logDebug(`Placeholder injected with ID: ph-${uniqueId}`);
      } catch (injectError) {
        console.error('[ImageGenExtension] Error injecting placeholder:', injectError);
        updateStatus(`❌ 错误：注入占位符失败: ${injectError.message}`, 'error');
        // Re-enable buttons if placeholder injection fails
        if (generateBtn?.length) generateBtn.prop('disabled', false);
        if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
        if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
        return; // Stop if placeholder fails
      }

      // --- Step 2.2: Call Gemini IMAGE API ---
      try {
        // Removed aspect ratio logic as it's not supported by the API endpoint
        const generationConfig = { responseModalities: ['TEXT', 'IMAGE'] };

        const requestBody = JSON.stringify({
          contents: [{ parts: [{ text: finalImagePrompt }] }],
          generationConfig: generationConfig, // Use the standard config
        });
        const headers = { 'Content-Type': 'application/json' };
        const apiUrlWithKey = `${GEMINI_IMAGE_API_ENDPOINT}?key=${userApiKey}`;

        logDebug('--- Gemini Image API Call ---');
        logDebug('Final Prompt (Sent to API):', finalImagePrompt);
        logDebug('Requesting Image URL:', apiUrlWithKey);

        const response = await fetch(apiUrlWithKey, { method: 'POST', headers: headers, body: requestBody });

        if (!response.ok) {
          let errorMsg = `Gemini 图片生成请求失败 (${response.status} ${response.statusText})`;
          let errorDataText = await response.text();
          try {
            errorMsg += ` - ${JSON.parse(errorDataText).error?.message || errorDataText}`;
          } catch (e) {
            errorMsg += ` - ${errorDataText}`;
          }
          throw new Error(errorMsg);
        }

        const data = await response.json();
        logDebug('Gemini Image API Success Response:', data);

        let imageDataFound = false;
        if (data.candidates && data.candidates[0]?.content?.parts) {
          for (const part of data.candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.data) {
              const inlineData = part.inlineData;
              const originalImageUrl = `data:${inlineData.mimeType || 'image/png'};base64,${inlineData.data}`;
              imageDataFound = true;
              updateStatus('✅ [2/2] (Gemini) 图片生成成功！正在替换占位符...', 'success'); // Removed scaling status

              try {
                logDebug(`Original Gemini image data length: ${originalImageUrl.length}`);
                // Removed call to resizeImageBase64

                // --- Step 2.3: Replace Placeholder with Original Image (with delay) ---
                const finalImageHtml = `<img src="${originalImageUrl}" alt="AI 生成的图片 (Gemini): ${escapeHtml(
                  finalImagePrompt,
                )}" style="max-width: ${MAX_DISPLAY_WIDTH}px; max-height: ${MAX_DISPLAY_HEIGHT}px; display: block; margin-top: 5px; border-radius: 5px;">`; // Use original URL, keep max display size style
                setTimeout(() => {
                    replacePlaceholderWithImage(uniqueId, finalImageHtml);
                    logDebug('Original Gemini image replaced placeholder.'); // Updated log
                }, 200); // Add 200ms delay

                updateStatus('✅ [2/2] (Gemini) 图片生成并已显示在聊天中！', 'success'); // Updated status
                // Update popup placeholder (optional, show original image)
                if (imageResult?.length)
                  imageResult.attr('src', originalImageUrl).attr('alt', `图片已注入聊天框 (ID: ${uniqueId})`); // Show original
              } catch (processError) { // Catch errors during placeholder replacement
                console.error(
                  '[ImageGenExtension] Error replacing placeholder for Gemini image:', // Updated error message
                  processError,
                );
                const errorHtml = `<span style="color: lightcoral;">❌ 处理或替换占位符失败: ${escapeHtml(
                  processError.message,
                )}</span>`;
                setTimeout(() => replacePlaceholderWithImage(uniqueId, errorHtml), 100); // Update placeholder with error (shorter delay ok)
                updateStatus('❌ [2/2] (Gemini) 图片生成成功，但处理或替换占位符失败。', 'error');
                if (imageResult?.length) imageResult.attr('src', '').attr('alt', '图片处理或替换占位符失败');
              } finally {
                // Re-enable buttons after generation and processing attempt
                if (generateBtn?.length) generateBtn.prop('disabled', false);
                if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
                if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
              }
              break; // Exit loop once image data is found and processed
            }
          }
        }

        if (!imageDataFound) {
          console.error('No image data found in Gemini response. Parts:', data.candidates?.[0]?.content?.parts);
          console.error('Full Gemini Image API Response:', data);
          let reason = '未能从中提取图片数据。';
          let detailedReason = '请检查控制台。';
          let finishReason = data.candidates?.[0]?.finishReason;
          let responseText = data.candidates?.[0]?.content?.parts?.find(p => p.text)?.text || '';
          if (finishReason === 'SAFETY') {
            reason = '图片可能因安全设置被阻止。';
            detailedReason = `完成原因: SAFETY. ${responseText}`;
          } else if (finishReason) {
            reason = `图片生成可能已停止。`;
            detailedReason = `完成原因: ${finishReason}. ${responseText}`;
          } else if (responseText) {
            reason = 'API响应中未找到图片数据，但包含文本：';
            detailedReason = responseText;
          }
          throw new Error(`Gemini API 成功响应，但${reason} ${detailedReason}`);
        }
      } catch (error) {
        console.error('Error generating Gemini image:', error);
        const errorHtml = `<span style="color: lightcoral;">❌ 图片生成错误 (Gemini): ${escapeHtml(
          error.message,
        )}</span>`;
        setTimeout(() => replacePlaceholderWithImage(uniqueId, errorHtml), 100); // Update placeholder with error (shorter delay ok)
        updateStatus(`❌ [2/2] (Gemini) 图片生成错误: ${error.message}`, 'error');
        if (imageResult?.length) imageResult.attr('alt', '生成失败 (Gemini)');
        if (
          error.message.includes('401') ||
          error.message.includes('403') ||
          error.message.toLowerCase().includes('api key not valid')
        ) {
          if (popupIsOpen) {
            const apiKeyStatus = popupInstance.find('#apiKeyStatus');
            if (apiKeyStatus?.length) apiKeyStatus.text('✗ 认证失败').css('color', 'lightcoral');
          }
          updateStatus(`❌ 错误：Gemini API Key 无效或权限不足。(${error.message})`, 'error');
        }
        // Re-enable buttons on error
        if (generateBtn?.length) generateBtn.prop('disabled', false);
        if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
        if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
      }
    } else if (selectedBackend === 'local_sd') {
      // --- Local SD Specific Processing ---
      updateStatus('⏳ [2/2] (Local SD) 正在生成图片...', 'info');
      const apiUrl = localStorage.getItem(LOCAL_SD_API_URL_STORAGE_KEY);
      const negativePrompt =
        localStorage.getItem(LOCAL_SD_NEGATIVE_PROMPT_STORAGE_KEY) || DEFAULT_LOCAL_SD_NEGATIVE_PROMPT;

      if (!apiUrl || !apiUrl.trim().startsWith('http')) {
        updateStatus('❌ 错误：请先在本地 SD 设置中输入有效的 API URL (例如 http://127.0.0.1:7860)。', 'error');
        if (popupIsOpen) {
          popupInstance.find('#localSdApiUrlInput')?.focus();
          // Ensure SD settings are visible
          popupInstance.find('#local-sd-settings-container').addClass('active');
          popupInstance.find('#gemini-settings-container').removeClass('active');
          popupInstance.find('input[name="imageGenBackend"][value="local_sd"]').prop('checked', true);
        }
        if (generateBtn?.length) generateBtn.prop('disabled', false);
        if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
        if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
        return;
      }

      // Note: We use the 'rawImagePrompt' directly from Gemini Text API for SD positive prompt.
      // We skip the Gemini negative keyword replacement and truncation for SD.
      finalImagePrompt = rawImagePrompt; // Use the prompt as generated by Gemini Text API
      if (promptInput?.length) promptInput.val(finalImagePrompt); // Update UI with the prompt used

      if (imageResult?.length) imageResult.attr('alt', '正在生成 (Local SD)...');

      // Reverted: Use default SD size (e.g., 512x512) as user indicated SD is not the performance bottleneck
      const defaultSdWidth = 512;
      const defaultSdHeight = 512;
      logDebug(`Requesting Local SD image size: ${defaultSdWidth}x${defaultSdHeight}`);

      const payload = {
        prompt: finalImagePrompt,
        negative_prompt: negativePrompt,
        steps: 25, // Example default
        cfg_scale: 7, // Example default
        width: defaultSdWidth, // Use default size
        height: defaultSdHeight, // Use default size
        // Add other parameters as needed, e.g., sampler_name, seed, etc.
        // sampler_name: "Euler a",
        // seed: -1,
      };

      logDebug('--- Local SD API Call ---');
      logDebug('API URL:', apiUrl.trim() + '/sdapi/v1/txt2img');
      logDebug('Payload:', payload);

      // --- Step 2.1: Inject Placeholder (Local SD) ---
      const uniqueId = generateUniqueId(); // Generate unique ID for SD placeholder
      const placeholderHtml = `<span id="ph-${uniqueId}">⏳ [AI 画图中 (Local SD)... ${escapeHtml(
        finalImagePrompt.substring(0, 50),
      )}...]</span>`;
      try {
        await TavernHelper_API.createChatMessages(
          [{ name: '图像生成系统', message: placeholderHtml, is_user: false, is_system: true, is_hidden: false }],
          { refresh: 'lazy' },
        );
        logDebug(`Placeholder injected for Local SD with ID: ph-${uniqueId}`);
      } catch (injectError) {
        console.error('[ImageGenExtension] Error injecting placeholder for Local SD:', injectError);
        updateStatus(`❌ 错误：注入 SD 占位符失败: ${injectError.message}`, 'error');
        // Re-enable buttons if placeholder injection fails
        if (generateBtn?.length) generateBtn.prop('disabled', false);
        if (saveApiKeyBtn?.length) saveApiKeyBtn.prop('disabled', false);
        if (saveSdSettingsBtn?.length) saveSdSettingsBtn.prop('disabled', false);
        return; // Stop if placeholder fails
      }

      // --- Step 2.2: Call Local SD API ---
      try {
        // Use GM_xmlhttpRequest for cross-origin requests if needed in Tampermonkey
        if (typeof GM_xmlhttpRequest === 'function') {
          GM_xmlhttpRequest({
            method: 'POST',
