  function bindMainPopupEvents(popupContent$) {
    logDebug('Binding main popup events (v0.1.11)...'); // Updated version
    if (!jQuery_API || !popupContent$ || popupContent$.length === 0 || typeof popupContent$.off !== 'function') {
      logDebug('bindMainPopupEvents: jQuery_API or popupContent$ is invalid.');
      return;
    }

    const statusDiv = popupContent$.find('#status');
    const geminiSettingsContainer = popupContent$.find('#gemini-settings-container');
    const localSdSettingsContainer = popupContent$.find('#local-sd-settings-container');

    // --- Function to toggle settings visibility ---
    const updateSettingsVisibility = selectedBackend => {
      if (selectedBackend === 'local_sd') {
        geminiSettingsContainer.removeClass('active');
        localSdSettingsContainer.addClass('active');
      } else {
        // Default to gemini
        geminiSettingsContainer.addClass('active');
        localSdSettingsContainer.removeClass('active');
      }
      logDebug(`Settings visibility updated for backend: ${selectedBackend}`);
    };

    // --- Bind Backend Selection Radio Buttons ---
    const backendRadios = popupContent$.find('input[name="imageGenBackend"]');
    backendRadios.off('change').on('change', function () {
      // Use jQuery's 'this' which refers to the changed radio button
      const selectedBackend = jQuery_API(this).val();
      localStorage.setItem(IMAGE_GEN_BACKEND_STORAGE_KEY, selectedBackend);
      updateSettingsVisibility(selectedBackend);
    });

    // --- Bind Gemini Settings Buttons ---
    const saveApiKeyBtn = popupContent$.find('#saveApiKeyBtn');
    const apiKeyInputElem = popupContent$.find('#apiKeyInput');
    const apiKeyStatusElem = popupContent$.find('#apiKeyStatus');
    if (saveApiKeyBtn.length) {
      saveApiKeyBtn.off('click').on('click', function (event) {
        event.stopPropagation();
        const apiKey = apiKeyInputElem.val()?.trim() || '';
        if (apiKey) {
          localStorage.setItem(GEMINI_API_KEY_STORAGE_KEY, apiKey);
          apiKeyStatusElem.text('✓ 已保存').css('color', 'lightgreen');
          statusDiv.text('Gemini API Key 已保存。').attr('class', 'status-success');
          logDebug('Gemini API Key saved.');
        } else {
          localStorage.removeItem(GEMINI_API_KEY_STORAGE_KEY);
          apiKeyStatusElem.text('✗ 未设置').css('color', 'lightcoral');
          statusDiv.text('Gemini API Key 不能为空！').attr('class', 'status-error');
          logDebug('Gemini API Key removed.');
        }
      });
    } else {
      logDebug('Save API Key button not found.');
    }

    const savePromptsBtn = popupContent$.find('#savePromptsBtn');
    const restorePromptsBtn = popupContent$.find('#restoreDefaultPromptsBtn');
    const systemPromptInput = popupContent$.find('#systemPromptInput');
    const stylePromptInput = popupContent$.find('#stylePromptInput');
    if (savePromptsBtn.length) {
      savePromptsBtn.off('click').on('click', function (event) {
        event.stopPropagation();
        const components = { system: systemPromptInput.val(), style: stylePromptInput.val() };
        try {
          localStorage.setItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY, JSON.stringify(components));
          statusDiv.text('提示词生成模板已保存。').attr('class', 'status-success');
          logDebug('Prompt components saved.');
        } catch (e) {
          console.error('Error saving prompt components:', e);
          statusDiv.text('保存模板失败，请检查控制台。').attr('class', 'status-error');
        }
      });
    } else {
      logDebug('Save Prompts button not found.');
    }

    if (restorePromptsBtn.length) {
      restorePromptsBtn.off('click').on('click', function (event) {
        event.stopPropagation();
        systemPromptInput.val(DEFAULT_SYSTEM_PROMPT);
        stylePromptInput.val(DEFAULT_STYLE_PROMPT);
        localStorage.removeItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY);
        statusDiv.text('提示词生成模板已恢复为默认。').attr('class', 'status-info');
        logDebug('Prompt components restored.');
      });
    } else {
      logDebug('Restore Default Prompts button not found.');
    }

    const saveGeminiNegKeywordsBtn = popupContent$.find('#saveGeminiNegKeywordsBtn');
    const restoreGeminiNegKeywordsBtn = popupContent$.find('#restoreDefaultGeminiNegKeywordsBtn');
    const geminiNegKeywordsInput = popupContent$.find('#geminiNegativeKeywordsInput');
    if (saveGeminiNegKeywordsBtn.length) {
      saveGeminiNegKeywordsBtn.off('click').on('click', function (event) {
        event.stopPropagation();
        const keywordsArray = geminiNegKeywordsInput
          .val()
          .split('\n')
          .map(kw => kw.trim())
          .filter(kw => kw !== '');
        try {
          localStorage.setItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY, JSON.stringify(keywordsArray));
          statusDiv.text('Gemini 禁词列表已保存。').attr('class', 'status-success');
          logDebug('Gemini negative keywords saved:', keywordsArray);
        } catch (e) {
          console.error('Error saving Gemini negative keywords:', e);
          statusDiv.text('保存 Gemini 禁词列表失败。').attr('class', 'status-error');
        }
      });
    } else {
      logDebug('Save Gemini Negative Keywords button not found.');
    }

    if (restoreGeminiNegKeywordsBtn.length) {
      restoreGeminiNegKeywordsBtn.off('click').on('click', function (event) {
        event.stopPropagation();
        geminiNegKeywordsInput.val(DEFAULT_GEMINI_NEGATIVE_KEYWORDS.join('\n'));
        localStorage.removeItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY);
        statusDiv.text('Gemini 禁词列表已恢复为默认。').attr('class', 'status-info');
        logDebug('Gemini negative keywords restored.');
      });
    } else {
      logDebug('Restore Default Gemini Negative Keywords button not found.');
    }

    // --- Removed Gemini Aspect Ratio Binding (API Incompatible) ---

    // --- Bind Local SD Settings Buttons ---
    const saveSdSettingsBtn = popupContent$.find('#saveSdSettingsBtn');
    const restoreSdNegPromptBtn = popupContent$.find('#restoreDefaultSdNegPromptBtn');
    const localSdApiUrlInput = popupContent$.find('#localSdApiUrlInput');
    const localSdNegativePromptInput = popupContent$.find('#localSdNegativePromptInput');

    if (saveSdSettingsBtn.length) {
      saveSdSettingsBtn.off('click').on('click', function (event) {
        event.stopPropagation();
        const apiUrl = localSdApiUrlInput.val()?.trim() || '';
        const negPrompt = localSdNegativePromptInput.val(); // Keep trailing spaces if user wants

        if (apiUrl) {
          localStorage.setItem(LOCAL_SD_API_URL_STORAGE_KEY, apiUrl);
        } else {
          localStorage.removeItem(LOCAL_SD_API_URL_STORAGE_KEY);
        }
        localStorage.setItem(LOCAL_SD_NEGATIVE_PROMPT_STORAGE_KEY, negPrompt);

        statusDiv.text('本地 SD 设置已保存。').attr('class', 'status-success');
        logDebug('Local SD settings saved. URL:', apiUrl, 'Negative Prompt:', negPrompt);
      });
    } else {
      logDebug('Save SD Settings button not found.');
    }

    if (restoreSdNegPromptBtn.length) {
      restoreSdNegPromptBtn.off('click').on('click', function (event) {
        event.stopPropagation();
        localSdNegativePromptInput.val(DEFAULT_LOCAL_SD_NEGATIVE_PROMPT);
        // Don't remove the key, just set to default value in textarea
        // localStorage.removeItem(LOCAL_SD_NEGATIVE_PROMPT_STORAGE_KEY); // Keep saved value unless explicitly saved over
        statusDiv
          .text('本地 SD 负面提示词已在文本框中恢复为默认（点击保存 SD 设置以存储）。')
          .attr('class', 'status-info');
        logDebug('Local SD negative prompt restored to default in textarea.');
      });
    } else {
      logDebug('Restore Default SD Negative Prompt button not found.');
    }

    // --- Bind Generate Image Button ---
    const generateBtn = popupContent$.find('#generateImageBtn');
    if (generateBtn.length) {
      generateBtn.off('click').on('click', async function (event) {
        event.stopPropagation();
        await generateImageFromContext();
      });
    } else {
      logDebug('Generate Image button not found.');
    }

    // --- Load Data on Popup Open ---

    // Load Backend Selection
    const savedBackend = localStorage.getItem(IMAGE_GEN_BACKEND_STORAGE_KEY) || 'gemini';
    popupContent$.find(`input[name="imageGenBackend"][value="${savedBackend}"]`).prop('checked', true);
    updateSettingsVisibility(savedBackend); // Show/hide sections based on loaded value

    // Load Gemini Data
    const savedApiKey = localStorage.getItem(GEMINI_API_KEY_STORAGE_KEY);
    if (savedApiKey) {
      apiKeyInputElem.val(savedApiKey);
      apiKeyStatusElem.text('✓ 已加载').css('color', 'lightgreen');
    } else {
      apiKeyStatusElem.text('✗ 未设置').css('color', 'lightcoral');
    }

    let loadedComponents = { system: DEFAULT_SYSTEM_PROMPT, style: DEFAULT_STYLE_PROMPT };
    const savedComponentsJson = localStorage.getItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY);
    if (savedComponentsJson) {
      try {
        const parsed = JSON.parse(savedComponentsJson);
        if (typeof parsed.system === 'string' && typeof parsed.style === 'string') {
          loadedComponents = parsed;
        } else {
          localStorage.removeItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY);
        }
      } catch (e) {
        localStorage.removeItem(GEMINI_PROMPT_COMPONENTS_STORAGE_KEY);
      }
    }
    systemPromptInput.val(loadedComponents.system);
    stylePromptInput.val(loadedComponents.style);

    let loadedGeminiNegKeywords = DEFAULT_GEMINI_NEGATIVE_KEYWORDS;
    const savedGeminiNegKeywordsJson = localStorage.getItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY);
    if (savedGeminiNegKeywordsJson) {
      try {
        const parsed = JSON.parse(savedGeminiNegKeywordsJson);
        if (Array.isArray(parsed) && parsed.every(item => typeof item === 'string')) {
          loadedGeminiNegKeywords = parsed;
        } else {
          localStorage.removeItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY);
        }
      } catch (e) {
        localStorage.removeItem(GEMINI_NEGATIVE_KEYWORDS_STORAGE_KEY);
      }
    }
    geminiNegKeywordsInput.val(loadedGeminiNegKeywords.join('\n'));

    // --- Removed Gemini Aspect Ratio Loading (API Incompatible) ---

    // Load Local SD Data
    const savedSdUrl = localStorage.getItem(LOCAL_SD_API_URL_STORAGE_KEY);
    if (savedSdUrl) {
      localSdApiUrlInput.val(savedSdUrl);
    }
    const savedSdNegPrompt = localStorage.getItem(LOCAL_SD_NEGATIVE_PROMPT_STORAGE_KEY);
    // Load saved value if exists, otherwise load default
    localSdNegativePromptInput.val(savedSdNegPrompt !== null ? savedSdNegPrompt : DEFAULT_LOCAL_SD_NEGATIVE_PROMPT);

    // Clear previous results
    statusDiv.text('').attr('class', '');
    popupContent$.find('#imageResult').attr('src', '').attr('alt', '生成的图片将注入聊天框'); // Update placeholder text
    popupContent$.find('#imagePrompt').val('');
  }

  function setupExtensionMenuItem() {
    logDebug('Setting up Image Gen menu item (v0.1.11)...'); // Updated version
    const parentDoc = SillyTavern_API?.Chat?.document
      ? SillyTavern_API.Chat.document
      : (window.parent || window).document;
    if (!parentDoc || !jQuery_API) return false;
    const extensionsMenu = jQuery_API('#extensionsMenu', parentDoc);
    if (!extensionsMenu.length) return false;

    if (jQuery_API(`#${EXTENSION_MENU_ITEM_CONTAINER_ID}`, extensionsMenu).length > 0) {
      extensionsMenu
        .find(`#${EXTENSION_MENU_ITEM_ID}`)
        .off('click.imageGen')
        .on('click.imageGen', event => {
          event.stopPropagation();
          showMainPopup();
        });
      return true;
    }

    const menuItemContainer = jQuery_API(
      `<div class="extension_container interactable" id="${EXTENSION_MENU_ITEM_CONTAINER_ID}" tabindex="0"></div>`,
    );
    const menuItem = jQuery_API(
      `<div title="打开${BUTTON_TEXT}" class="list-group-item flex-container flexGap5 interactable" id="${EXTENSION_MENU_ITEM_ID}"><div class="fa-fw fa-solid fa-paint-brush extensionsMenuExtensionButton"></div><span>${BUTTON_TEXT}</span></div>`,
    );

    menuItem.on('click.imageGen', event => {
      event.stopPropagation();
      const extensionsMenuButton = jQuery_API('#extensionsMenuButton', parentDoc);
      if (extensionsMenuButton.length && extensionsMenu.is(':visible')) {
        extensionsMenuButton.trigger('click');
        setTimeout(showMainPopup, 150);
      } else {
        showMainPopup();
      }
    });

    menuItemContainer.append(menuItem);
    extensionsMenu.append(menuItemContainer);
    logDebug('Image Gen menu item added.');
    return true;
  }

  async function showMainPopup() {
    logDebug('--- showMainPopup called ---');
    if (!coreApisAreReady && !attemptToLoadCoreApis()) {
      (toastr_API || alert)('无法打开图像生成器：核心组件加载失败。');
      return;
    }
    try {
      const popupContentHtml = createMainPopupHtml();
      const popupContentForDisplay = jQuery_API(popupContentHtml);
      SillyTavern_API.callGenericPopup(popupContentForDisplay, SillyTavern_API.POPUP_TYPE.DISPLAY, BUTTON_TEXT, {
        wide: true,
        large: true,
        allowVerticalScrolling: true,
      })
        .then(() => logDebug('Image Gen popup closed.'))
        .catch(err => {
          console.error('[ImageGenExtension] Popup error:', err);
          toastr_API?.error(`显示弹窗错误: ${err.message}`);
        });
      // Delay binding slightly longer to ensure popup DOM is fully ready
      setTimeout(() => {
        const currentPopupInstance = jQuery_API(`dialog[open]:not([closing]) #${MAIN_POPUP_ID}`);
        if (currentPopupInstance.length > 0) {
          bindMainPopupEvents(currentPopupInstance);
          logDebug('Events bound to popup.');
        } else {
          logDebug('Popup instance not found for binding after delay.');
        }
      }, 400); // Increased delay slightly
    } catch (error) {
      console.error('[ImageGenExtension] Error in showMainPopup:', error);
      toastr_API?.error(`显示图像生成器出错: ${error.message}`);
    }
  }

  const maxInitAttempts = 20;
  const initInterval = 1500;
  let initAttempts = 0;

  function mainInitialize() {
    initAttempts++;
    logDebug(`Main Initialization Attempt ${initAttempts}/${maxInitAttempts} (v0.1.11)`); // Updated version

    if (attemptToLoadCoreApis()) {
      if (setupExtensionMenuItem()) {
        logDebug('Image Gen initialized successfully.');
        toastr_API?.success(`${BUTTON_TEXT} (v0.1.11) 已整合!`, '图像生成扩展', { timeOut: 4000 }); // Updated version
        if (!eventListenersAttached) {
          try {
            const reSetupMenuItemOnUIChange = () => {
              setupExtensionMenuItem();
            };
            // Use newer event handling if available
            if (TavernHelper_API?.eventOn && TavernHelper_API?.tavern_events) {
              TavernHelper_API.eventRemoveListener(
                TavernHelper_API.tavern_events.CHAT_CHANGED,
                reSetupMenuItemOnUIChange,
              );
              TavernHelper_API.eventOn(TavernHelper_API.tavern_events.CHAT_CHANGED, reSetupMenuItemOnUIChange);
              TavernHelper_API.eventRemoveListener(
                TavernHelper_API.tavern_events.GROUP_UPDATED,
                reSetupMenuItemOnUIChange,
              );
              TavernHelper_API.eventOn(TavernHelper_API.tavern_events.GROUP_UPDATED, reSetupMenuItemOnUIChange);
            } else if (SillyTavern_API?.tavern_events?.on) {
              // Fallback for older versions
              SillyTavern_API.tavern_events.on('CHAT_CHANGED', reSetupMenuItemOnUIChange);
              SillyTavern_API.tavern_events.on('GROUP_UPDATED', reSetupMenuItemOnUIChange);
            }
            eventListenersAttached = true;
          } catch (e) {
            console.error('[ImageGenExtension] Error setting up UI change listeners:', e);
          }
        }

        // --- Register External Button ---
        if (typeof eventOnButton === 'function') {
          try {
            eventOnButton('生图', generateImageFromContext);
            logDebug('External button "生图" registered using global eventOnButton.');
          } catch (e) {
            console.error(
              '[ImageGenExtension] Error registering external button "生图" using global eventOnButton:',
              e,
            );
            toastr_API?.warning('注册外部按钮 "生图" 失败，请检查控制台。');
          }
        } else {
          console.warn(
            '[ImageGenExtension] Global eventOnButton function is not available. Cannot register "生图" button event.',
          );
        }

        return; // Success
      }
    }

    if (initAttempts < maxInitAttempts) {
      setTimeout(mainInitialize, initInterval);
    } else {
      const errorMsg = '[ImageGenExtension] Failed to initialize after multiple attempts.';
      console.error(errorMsg);
      (toastr_API || alert)(errorMsg);
    }
  }

  const getReadyState = () => {
    try {
      return (window.parent || window).document.readyState;
    } catch (e) {
      // Catch potential cross-origin errors if parent is inaccessible
      return document.readyState;
    }
  };
  const initialLoadDelay = 2500;

  const starterFunction = () => {
    if (starterFunctionCalled) return;
    starterFunctionCalled = true;
    logDebug('Document ready. Starting ImageGenExtension v0.1.11 initialization.'); // Updated version
    mainInitialize();
  };

  // Use a unique flag for this script version
  const scriptLoadedFlag = 'ImageGenExtensionV0111Loaded'; // Updated flag
  if (typeof window[scriptLoadedFlag] === 'undefined') {
    window[scriptLoadedFlag] = true;
    if (getReadyState() === 'complete') {
      setTimeout(starterFunction, initialLoadDelay);
    } else {
      (window.parent || window).addEventListener('load', starterFunction, { once: true });
    }
  } else {
    console.log('[ImageGenExtension v0.1.11] Script already loaded.'); // Updated version
  }
})();
